parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    let parsed;
    try {
      const text = item.json.content[0].text;
      parsed = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      parsed = match ? JSON.parse(match[0]) : {adapted_posts: []};
    }
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      adapted_posts: parsed.adapted_posts || [],
      instagram_caption: parsed.adapted_posts && parsed.adapted_posts[0] ? parsed.adapted_posts[0].adapted_caption : '',
      instagram_caption_2: parsed.adapted_posts && parsed.adapted_posts[1] ? parsed.adapted_posts[1].adapted_caption : '',
      facebook_post: parsed.adapted_posts && parsed.adapted_posts[2] ? parsed.adapted_posts[2].adapted_caption : '',
      content_theme: 'viral_adapted',
      status: 'pending_approval',
      created_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
